SELECT sentiment_id, AVG(sentiment_score) AS avg_sentiment_score
FROM conversation_sentiments
GROUP BY sentiment_id;

SELECT conversation_id, SQRT(sentiment_score) as sentiment_sqrt
FROM conversation_sentiments
WHERE created_by = 0;

SELECT conversation_id, AVG(sentiment_score) AS average_sentiment_score, COUNT(sentiment_id) AS sentiment_count
FROM conversation_sentiments
GROUP BY conversation_id;

SELECT AVG(cs.sentiment_score) AS overall_average_sentiment_score
FROM conversations c
JOIN conversation_sentiments cs ON c.conversation_id = cs.conversation_id;

SELECT COUNT(*) 
FROM conversation_sentiments 
WHERE sentiment_score > 0.5;
